INSERT INTO quiz_question (id, word_bank_id, contextual_cloze, chinese_translation, correct_answer, distractor1, distractor2, distractor3, explanation_root_affix, explanation_mnemonic, created_at, updated_at) VALUES
('9f17bd22-4b39-5b0c-97f8-60ca23eafb84', 'c2ab26ec-13c3-4c73-a8ed-ac40bb801088', '___ of the students passed the exam because it was very easy.', '因為考試非常簡單，所有的學生都通過了。', 'All', 'Some', 'Many', 'Few', 'All 沒有特定的字根，在此作為代名詞，表示「全部」。', '想像一個大圓圈，把所有東西都包進去，那就是 all。', '2026-07-06 13:45:09', '2026-07-06 13:45:09'),
('595bbf02-dc38-5c8d-b4af-0b543e61ad28', '083e97dd-65dd-44aa-a37e-61a7b821c846', 'He likes to study ___ in the library.', '他喜歡在圖書館獨自學習。', 'alone', 'loudly', 'quickly', 'happily', 'alone 由 all (全部) 與 one (一個) 組合而成，表示只有一個人。', 'all (全部) + one (一個) → 只有一個 → 單獨地。', '2026-07-06 13:48:51', '2026-07-06 13:48:51'),
('7275e524-c0a9-5bd2-a986-f1b9e198c60c', 'c54b1ef7-6733-4354-a00a-be55ef775061', 'As the hikers climbed higher, they began to feel dizzy because of the thinning air at high ___.', '隨著登山者不斷向上攀爬，由於高海拔處空氣稀薄，他們開始感到頭暈。', 'altitude', 'density', 'depth', 'temperature', '來自拉丁語 altus，代表「高的」(high)。', 'alt (高) + itude (名詞字尾) → 高度、海拔。', '2026-07-06 20:24:49', '2026-07-06 20:24:49'),
('1d6a3002-5d1a-5e14-9fca-374b57358d18', 'd4eae649-8fe4-4b88-97a2-fcdcfc485e69', 'I need to call the clinic to reschedule my ___ with the doctor.', '我需要打電話給診所，重新安排我與醫生的預約。', 'appointment', 'achievement', 'tradition', 'direction', 'ap- (趨向/去) + point (點/位置) → 把某人或某事安排到某個位置或時間 → 約定、任命。', 'point 是『點』，把時間或位置『點』好，就是『約定』。', '2026-07-06 23:12:35', '2026-07-06 23:12:35'),
('be54e2bf-717e-540f-a3c7-b1e60a204348', '396af8ba-dc90-47e2-8fe7-a7e275c84c35', 'The professor decided to give a challenging group ___ to help students practice their teamwork skills.', '教授決定給一個具挑戰性的分組作業，以幫助學生練習團隊合作技巧。', 'assignment', 'achievement', 'arrangement', 'appointment', 'assign (指派) + -ment (名詞字尾) → 任務、作業', 'assign (指派) 加上名詞字尾 -ment，表示被指派下來的任務或作業。', '2026-07-07 01:19:17', '2026-07-07 01:19:17'),
('d3d8f056-2791-54f0-a431-d1eff5644378', '52086b76-9ecc-4722-9a66-f281c4f94548', 'The magician''s unexpected performance is enough to ___ the entire audience.', '魔術師那出乎意料的表演足以讓全場觀眾感到吃驚。', 'astonish', 'convince', 'ignore', 'assist', '字根解析：astonish 源自於 stun (使震驚)，加上前綴 a- 表示進入一種震驚的狀態。', '記憶法：想像一個人因為太吃驚而像變成了一塊『石頭 (stone)』一樣呆立原地。 → stone (石頭) → astonish (使吃驚)。', '2026-07-07 01:36:00', '2026-07-07 01:36:00'),
('e8e87e56-56ac-552d-a78f-b2eaf0f25e48', 'a135908f-b8e9-4c52-8cc5-16e52a6061a1', 'He has always been interested in ___ and hopes to compete in the Olympics one day.', '他一直對體育運動很感興趣，並希望有一天能參加奧運。', 'athletics', 'literature', 'chemistry', 'politics', '字根 athlet- 意為「比賽」或「競賽」。', 'athlete (運動員) → athletics (體育運動)。', '2026-07-07 01:47:58', '2026-07-07 01:47:58'),
('077be9a1-3ca2-5456-a4ff-517355245a84', '7aff40ef-01c1-454b-9113-2e7542380ee8', 'You should wear a mask to ___ getting sick.', '你應該戴口罩來避免生病。', 'avoid', 'enjoy', 'start', 'forget', 'a- (去) + void (空) → 避開。', '把討厭的事情「空」掉，就是「避免」。', '2026-07-06 15:45:54', '2026-07-06 15:45:54'),
('c4a6a502-faf2-5807-aff8-0fd2dfce9228', 'b550c15d-7c8c-4036-ac4c-e4b84ccb6d6f', 'Please come ___ to the classroom after lunch.', '午餐後請回到教室。', 'back', 'fast', 'soon', 'away', 'back 在此作為副詞，表示回到原處。', 'come back 是回來的意思', '2026-07-07 01:44:50', '2026-07-07 01:44:50'),
('0ead3392-1d5b-5077-88e3-b8aa4995a584', '592302c9-f8a7-4793-bfb0-607d9cd26539', 'Our school basketball team finally managed to ___ the other team in the final game.', '我們學校的籃球隊終於在最後一場比賽中擊敗了另一支隊伍。', 'beat', 'find', 'help', 'join', 'beat 為不規則動詞，其變化形式為 beat → beat → beaten。', '想像在比賽中要「擊敗」對手，唸起來很像「必打」，一定要打贏對方！', '2026-07-07 02:46:56', '2026-07-07 02:46:56'),
('aa808db4-886e-54f1-a803-8d486854e558', 'b293dbac-05ff-4b8e-b6d5-a6e7825914b2', 'I have one ___ and one sister.', '我有一個兄弟和一個姊妹。', 'brother', 'friend', 'student', 'driver', '此字為單字，無特定字根。', 'brother 常用縮寫 bro 來稱呼好兄弟。', '2026-07-07 08:41:48', '2026-07-07 08:41:48'),
('ff73b067-e8d9-559c-97ed-1bd0743f7434', '43e71354-7db1-442e-b861-19feb8e2188e', 'My sister''s favorite toy is a beautiful ___ with long hair.', '我妹妹最喜歡的玩具是一個留著長頭髮的美麗洋娃娃。', 'doll', 'ball', 'kite', 'car', 'doll 為單一單字，無字根。', 'doll 讀音像「多喔」，想像玩洋娃娃玩得「多喔」！', '2026-07-07 05:04:49', '2026-07-07 05:04:49'),
('78520728-c072-5be6-acd6-7bc53f701790', 'cf6fbac6-b54b-4adc-a274-dd3fb40fa5e9', 'You can ___ stay at home or go to the cinema.', '你可以待在家裡或者去電影院。', 'either', 'always', 'never', 'often', 'either 與 or 連用，構成 either...or... 句型，表示「或者...或者...」。', '看到 or 就聯想到 either → either...or...', '2026-07-07 03:30:51', '2026-07-07 03:30:51'),
('f50bdee8-f880-51fb-a07c-27a9ceb874bc', '62636026-0251-407c-87f0-5f5233f0ce21', 'Apples are my ___ fruit because they are sweet and crunchy.', '蘋果是我最喜歡的水果，因為它們又甜又脆。', 'favorite', 'hungry', 'heavy', 'angry', 'root: favor (偏愛) + suffix: -ite (形成形容詞/名詞)', 'favor (好感) + ite → favorite (最喜愛的)', '2026-07-07 05:16:25', '2026-07-07 05:16:25'),
('2ca1b100-e6de-5903-b968-d5b70b5d1b84', '8014755c-2a80-466f-a06a-c53a888c0b81', 'My father loves cooking. ___ makes delicious food.', '我的父親很喜歡烹飪。他做出的食物很美味。', 'He', 'She', 'It', 'We', '人稱代名詞，用來代替前面提到的男性名詞 father。', 'Father 是爸爸 → 用 He。', '2026-07-06 10:34:37', '2026-07-06 10:34:37'),
('c811cc48-dd2c-5162-a15c-2f143650f134', '3618111e-eb30-4e3b-b1bb-d7eb327585a6', 'I have a dog. ___ dog is big.', '我有一隻狗。我的狗很大。', 'my', 'your', 'his', 'her', 'my 為第一人稱單數的所有格，表示「我的」。', 'my (我的) → 記住 my 是用來指「我的」東西。', '2026-07-05 13:06:23', '2026-07-05 13:06:23'),
('2a2c8a91-7f86-57e4-a6e7-b3f2fd901044', 'e5cf7677-1873-4e7a-ae65-3de4832151b1', 'You should ___ a bus to the museum today.', '你今天應該搭公車去博物館。', 'take', 'sing', 'eat', 'see', 'take 表示「搭乘」交通工具。', 'take a bus → 搭公車。', '2026-07-05 07:32:25', '2026-07-05 07:32:25'),
('1b0d18b9-41a8-5123-a815-45d70bc46a78', 'a17db9fc-c01a-47c1-8d24-38406a541f61', 'Please hurry up; we don''t have much ___ to prepare for the upcoming presentation.', '請快一點；我們沒有太多時間為即將到來的簡報做準備。', 'time', 'space', 'money', 'chance', 'time 在此作為名詞，意為「時間」。', '記住 Time is money. (時間就是金錢)。', '2026-07-06 11:03:16', '2026-07-06 11:03:16'),
('ce1e93e7-6510-5562-97e6-622588d900b0', 'ab9949bb-c10f-4d67-8598-84d3e16ab7d5', 'The house ___ a beautiful garden is very expensive.', '那棟擁有美麗花園的房子非常貴。', 'with', 'by', 'for', 'at', '表示擁有或具有某種特徵。', '房子「帶有」花園。', '2026-07-05 14:43:44', '2026-07-05 14:43:44');
